18	{
19	    /// <summary>
20	    /// Represents a sortable, filterable data grid with multiselection, pagination, editing, grouping, aggregation, and server-side <see cref="IQueryable{T}"/> support.
21	    /// </summary>
22	    /// <typeparam name="T">The type of data represented by each row in this grid.</typeparam>
23	    [CascadingTypeParameter(nameof(T))]
24	    public partial class MudDataGrid<[DynamicallyAccessedMembers(DynamicallyAccessedMemberTypes.PublicProperties)] T> : MudComponentBase, IDisposable
25	    {
