33	        private bool _columnsPanelVisible = false;
34	        internal HashSet<T> _openHierarchies = [];
35	        private readonly HashSet<T> _initialExpansions = [];
36	        private Func<T, bool>? _initialExpandedFunc = null;
37	        private Func<T, bool>? _buttonDisabledFunc = null;
38	        private string _columnsPanelSearch = string.Empty;
39	        private MudDropContainer<Column<T>>? _dropContainer;
40	        private MudDropContainer<Column<T>>? _columnsPanelDropContainer;
41	        private readonly PropertyInfo[] _properties = typeof(T).GetProperties();
42	        private CancellationTokenSource? _serverDataCancellationTokenSource;
43	        private IEnumerable<T>? _currentRenderFilteredItemsCache = null;
44	        internal GroupDefinition<T>? _groupDefinition;
45	        internal Dictionary<GroupKey, bool> _groupExpansionsDict = [];
46	        private GridData<T> _serverData = new() { TotalItems = 0, Items = Array.Empty<T>() };
47	        private Func<IFilterDefinition<T>> _defaultFilterDefinitionFactory = () => new FilterDefinition<T>();
48	        internal (double Top, double Left) _openPosition = (0, 0);
49	
50	        private readonly ParameterState<T?> _selectedItemState;
51	        private readonly ParameterState<HashSet<T>?> _selectedItemsState;
52	        private readonly ParameterState<bool> _expandSingleRowState;
53	
54	        /// <summary>
55	        /// Inline data attributes for positioning the menu at the cursor's location.
56	        /// </summary>
57	        internal Dictionary<string, object> PositionAttributes => new()
58	        {
59	            { "data-pc-x", _openPosition.Left.ToString(CultureInfo.InvariantCulture) },
60	            { "data-pc-y", _openPosition.Top.ToString(CultureInfo.InvariantCulture) }
61	        };
62	
63	        public MudDataGrid()
64	        {
65	            Selection = new HashSet<T>(Comparer);
66	            SelectedItems = new HashSet<T>(Comparer);
67	            using var registerScope = CreateRegisterScope();
68	            registerScope.RegisterParameter<IEnumerable<T>?>(nameof(Items))
69	                .WithParameter(() => Items)
70	                .WithChangeHandler(OnItemsChangedAsync);
71	
72	            _selectedItemState = registerScope.RegisterParameter<T?>(nameof(SelectedItem))
73	                .WithParameter(() => SelectedItem)
74	                .WithEventCallback(() => SelectedItemChanged)
75	                .WithChangeHandler(OnSelectedItemChangedAsync);
76	
77	            _selectedItemsState = registerScope.RegisterParameter<HashSet<T>?>(nameof(SelectedItems))
78	                .WithParameter(() => SelectedItems)
79	                .WithEventCallback(() => SelectedItemsChanged)
80	                .WithChangeHandler(OnSelectedItemsChanged);
81	
82	            _expandSingleRowState = registerScope.RegisterParameter<bool>(nameof(ExpandSingleRow))
83	                .WithParameter(() => ExpandSingleRow)
84	                .WithChangeHandler(OnExpandSingleRowChangedAsync);
85	        }
86	
87	        protected string Classname =>
88	            new CssBuilder("mud-table")
89	                .AddClass("mud-data-grid")
90	                .AddClass("mud-xs-table", Breakpoint == Breakpoint.Xs)
91	                .AddClass("mud-sm-table", Breakpoint == Breakpoint.Sm)
92	                .AddClass("mud-md-table", Breakpoint == Breakpoint.Md)
93	                .AddClass("mud-lg-table", Breakpoint == Breakpoint.Lg || Breakpoint == Breakpoint.Always)
94	                .AddClass("mud-xl-table", Breakpoint == Breakpoint.Xl || Breakpoint == Breakpoint.Always)
95	                .AddClass("mud-table-dense", Dense)
96	                .AddClass("mud-table-hover", Hover)
97	                .AddClass("mud-table-bordered", Bordered)
98	                .AddClass("mud-table-striped", Striped)
99	                .AddClass("mud-table-outlined", Outlined)
100	                .AddClass("mud-table-square", Square)
101	                .AddClass("mud-table-sticky-header", FixedHeader)
102	                .AddClass("mud-table-sticky-footer", FixedFooter)
103	                .AddClass($"mud-elevation-{Elevation}", !Outlined)
104	                .AddClass(Class)
105	                .Build();
106	
107	        protected string Stylename =>
108	            new StyleBuilder()
109	                .AddStyle("overflow-x", "auto", when: HorizontalScrollbar || ColumnResizeMode == ResizeMode.Container)
110	                .AddStyle("position", "relative", when: HasStickyColumns)
111	                .AddStyle(Style)
112	                .Build();
113	
114	        protected string TableStyle =>
115	            new StyleBuilder()
116	                .AddStyle("height", Height, !string.IsNullOrWhiteSpace(Height))
117	                .AddStyle("width", "max-content", when: HorizontalScrollbar || ColumnResizeMode == ResizeMode.Container)
118	                .AddStyle("overflow", "clip", when: (HorizontalScrollbar || ColumnResizeMode == ResizeMode.Container) && HasStickyColumns)
119	                .AddStyle("display", "block", when: HorizontalScrollbar)
120	                .Build();
