            var icon = toggleButton.QuerySelector(".mud-icon-root");

            // Initial state should show expanded icon (ExpandMore)
            var iconPath = icon.InnerHtml;
            iconPath.Should().Contain("M16.59 8.59L12 13.17 7.41 8.59 6 10l6 6 6-6z",
