                Id = Guid.NewGuid(),
                Column = nameColumn,
                Operator = FilterOperator.String.Contains,
                Value = "A"
            }));
            comp.Instance.FilterChanged.Should().Be(true);
            comp.Instance.FilterChangedCallCount.Should().Be(1);

            await dataGrid.InvokeAsync(dataGrid.Instance.ClearFiltersAsync);
            comp.Instance.FilterChangedCallCount.Should().Be(2);

            // Fire SortChanged by adding, changing, and removing a sort
            await dataGrid.InvokeAsync(() => dataGrid.Instance.SetSortAsync(nameof(DataGridEventCallbacksTest.Item.Name), SortDirection.Ascending, x => x.Name));
            comp.Instance.SortChanged.Should().Be(true);
            comp.Instance.SortChangedCallCount.Should().Be(1);
            comp.Instance.SortChangedDefinitions.Should().ContainSingle();
            comp.Instance.SortChangedDefinitions!.Single().SortBy.Should().Be(nameof(DataGridEventCallbacksTest.Item.Name));
            comp.Instance.SortChangedDefinitions!.Single().Descending.Should().Be(false);

            await dataGrid.InvokeAsync(() => dataGrid.Instance.SetSortAsync(nameof(DataGridEventCallbacksTest.Item.Name), SortDirection.Descending, x => x.Name));
            comp.Instance.SortChangedCallCount.Should().Be(2);
            comp.Instance.SortChangedDefinitions.Should().ContainSingle();
            comp.Instance.SortChangedDefinitions!.Single().Descending.Should().Be(true);

            await dataGrid.InvokeAsync(() => dataGrid.Instance.RemoveSortAsync(nameof(DataGridEventCallbacksTest.Item.Name)));
            comp.Instance.SortChangedCallCount.Should().Be(3);
            comp.Instance.SortChangedDefinitions.Should().BeEmpty();
        }

